import{_ as o,C as n,o as s,c as l,E as r,w as i,a,a0 as u}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Moving to Luxembourg","description":"Immigration pathways and relocation guide for transgender people moving to Luxembourg","frontmatter":{"layout":"doc","title":"Moving to Luxembourg","description":"Immigration pathways and relocation guide for transgender people moving to Luxembourg"},"headers":[],"relativePath":"europe/luxembourg/moving-there.md","filePath":"europe/luxembourg/moving-there.md","lastUpdated":null}'),d={name:"europe/luxembourg/moving-there.md"};function c(g,e,m,h,f,p){const t=n("Badge");return s(),l("div",null,[r(t,{variant:"green"},{default:i(()=>[...e[0]||(e[0]=[a("EU Free Movement",-1)])]),_:1}),r(t,{variant:"yellow"},{default:i(()=>[...e[1]||(e[1]=[a("High Cost of Living",-1)])]),_:1}),e[2]||(e[2]=u('<h1 id="moving-to-luxembourg" tabindex="-1">Moving to Luxembourg <a class="header-anchor" href="#moving-to-luxembourg" aria-label="Permalink to &quot;Moving to Luxembourg&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>Luxembourg, as an EU member state, grants free movement rights to citizens of EU/EEA countries and Switzerland. EU citizens can enter Luxembourg with a valid ID card or passport. After three months of residence, registration with the commune is required.</p><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Visa (Salarié)</td><td>For employment with a Luxembourg-based company</td><td>Job offer, employment contract, qualification recognition</td><td>1 year, renewable</td></tr><tr><td>EU Blue Card</td><td>For highly qualified workers</td><td>Degree + salary threshold (approx. €58,000/year)</td><td>Up to 4 years</td></tr><tr><td>Family Reunification</td><td>For family members of Luxembourg residents</td><td>Relationship proof, sufficient income, accommodation</td><td>1 year, renewable</td></tr><tr><td>Job Seeker Visa</td><td>For job searching in Luxembourg</td><td>Proof of qualifications, sufficient funds, accommodation</td><td>3 months</td></tr><tr><td>Student Visa</td><td>For full-time study</td><td>University acceptance, sufficient funds</td><td>1 year, renewable</td></tr></tbody></table><h2 id="key-relocation-steps" tabindex="-1">Key Relocation Steps <a class="header-anchor" href="#key-relocation-steps" aria-label="Permalink to &quot;Key Relocation Steps&quot;">​</a></h2><ol><li><strong>Secure accommodation</strong> — Housing is very expensive and scarce; start searching early</li><li><strong>Register with the commune</strong> — Within 8 days of arrival (for stays over 3 months)</li><li><strong>Apply for a residence permit</strong> — Non-EU citizens must apply before arrival</li><li><strong>Register for health insurance</strong> — CNS registration is automatic for employees</li><li><strong>Open a bank account</strong> — Required for salary and many administrative processes</li><li><strong>Learn one of the official languages</strong> — French is most practical for daily life; Luxembourgish for citizenship</li></ol><h2 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h2><p>Luxembourg has one of the highest costs of living in Europe:</p><ul><li>Rent (1-bedroom in city centre): €1,500-2,200/month</li><li>Groceries: €400-600/month for one person</li><li>Public transport: Free throughout the country</li><li>Health insurance: Covered by CNS (employee contributions ~3.05% of salary)</li></ul><h2 id="trans-specific-relocation-tips" tabindex="-1">Trans-Specific Relocation Tips <a class="header-anchor" href="#trans-specific-relocation-tips" aria-label="Permalink to &quot;Trans-Specific Relocation Tips&quot;">​</a></h2><ul><li><strong>Bring copies of medical records</strong> translated into French or German</li><li><strong>Carry at least 3 months of HRT medication</strong> initially, with a doctor&#39;s letter</li><li><strong>Register with a GP</strong> near your residence; they can refer to endocrinology at CHL</li><li><strong>Connect with CIGALE</strong> for community support and trans-specific guidance</li><li><strong>Luxembourg City is very safe</strong> but smaller towns may have less awareness</li></ul><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><ul><li><strong>Official languages</strong>: Luxembourgish, French, German</li><li><strong>French</strong> is most commonly used in administrative and medical contexts</li><li><strong>English</strong> is widely spoken in business and at hospitals</li><li><strong>Luxembourgish</strong> is required for citizenship (oral exam)</li><li>Language classes are subsidised by the state</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Guichet.lu</strong> — Official government portal: <a href="https://guichet.public.lu/" target="_blank" rel="noreferrer">guichet.public.lu</a></li><li><strong>Ministry of Foreign Affairs</strong> — Immigration information: <a href="https://mae.lu/" target="_blank" rel="noreferrer">mae.lu</a></li><li><strong>ADEM</strong> — Employment agency: <a href="https://adem.lu/" target="_blank" rel="noreferrer">adem.lu</a></li><li><strong>CIGALE</strong> — Trans/LGBTIQ+ support: <a href="https://www.cigale.lu/" target="_blank" rel="noreferrer">cigale.lu</a></li></ul>',17))])}const x=o(d,[["render",c]]);export{y as __pageData,x as default};
